// 三载体一致:纯 JS 计算引擎,零 DOM/CSS/uplink/shadow 足迹
import { HyperFormula } from 'https://cdn.jsdelivr.net/npm/hyperformula@3/+esm';
const hf = HyperFormula.buildFromArray(data.sheet, { licenseKey: 'gpl-v3', ...(data.config ?? {}) });
const values = hf.getSheetValues(0); // CellValue[][],公式已按依赖图求值
// 交互重算:
for (const u of (data.updates ?? [])) hf.setCellContents(u.address, u.contents);
// 用完释放:hf.destroy();
